### 任务 4: 错误处理与重试机制
**优先级**: 🟡 **中高** | **预估工作量**: 2天

```typescript
// src/utils/retry.ts
export class RetryManager {
  async retry<T>(
    fn: () => Promise<T>,
    options: {
      maxAttempts?: number
      baseDelay?: number
      maxDelay?: number
      backoff?: 'exponential' | 'linear'
    } = {}
  ): Promise<T> {
    const {
      maxAttempts = 3,
      baseDelay = 1000,
      maxDelay = 10000,
      backoff = 'exponential'
    } = options

    let lastError: Error

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        return await fn()
      } catch (error) {
        lastError = error as Error

        if (attempt < maxAttempts) {
          const delay = Math.min(
            baseDelay * (backoff === 'exponential' ? 2 ** attempt : attempt),
            maxDelay
          )

          console.warn(`Attempt ${attempt} failed, retrying in ${delay}ms...`)
          await this.sleep(delay)
        }
      }
    }

    throw lastError!
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms))
  }
}

// 在 BaseAgent 中使用
export abstract class BaseAgent {
  protected retryManager = new RetryManager()

  async runWithRetry<T>(fn: () => Promise<T>): Promise<T> {
    return this.retryManager.retry(fn, {
      maxAttempts: 3,
      backoff: 'exponential'
    })
  }
}
```

