// src/monitoring/performance-collector.ts
export class PerformanceCollector {
  private metrics: Map<string, number[]> = new Map()

  recordAgentExecution(agentName: string, duration: number) {
    if (!this.metrics.has(agentName)) {
      this.metrics.set(agentName, [])
    }
    this.metrics.get(agentName)!.push(duration)
  }

  getStats(agentName: string) {
    const durations = this.metrics.get(agentName) || []

    if (durations.length === 0) return null

    const sorted = [...durations].sort((a, b) => a - b)

    return {
      count: durations.length,
      min: sorted[0],
      max: sorted[sorted.length - 1],
      avg: durations.reduce((a, b) => a + b, 0) / durations.length,
      p50: sorted[Math.floor(sorted.length * 0.5)],
      p95: sorted[Math.floor(sorted.length * 0.95)],
      p99: sorted[Math.floor(sorted.length * 0.99)]
    }
  }

  getAllStats() {
    return Object.fromEntries(
      Array.from(this.metrics.keys()).map(name => [
        name,
        this.getStats(name)
      ])
    )
  }
}
