### 任务4: 完善实时 WebSocket 通信 (P1)

**文件**: `src/dashboard/services/realtime.service.ts`

**需要完善的方法**:

```typescript
class RealtimeService {
  // 客户端订阅管理
  private subscriptions: Map<WebSocket, string[]> = new Map();

  subscribe(socket: WebSocket, channel: string) {
    if (!this.subscriptions.has(socket)) {
      this.subscriptions.set(socket, []);
    }
    this.subscriptions.get(socket)!.push(channel);
  }

  unsubscribe(socket: WebSocket, channel: string) {
    const channels = this.subscriptions.get(socket);
    if (channels) {
      const index = channels.indexOf(channel);
      if (index > -1) channels.splice(index, 1);
    }
  }

  // 广播到特定频道
  broadcastToChannel(channel: string, event: string, data: any) {
    this.clients.forEach(socket => {
      const channels = this.subscriptions.get(socket) || [];
      if (channels.includes(channel) || channels.includes('all')) {
        socket.send(JSON.stringify({ event, data }));
      }
    });
  }
}
```

