// 文件: src/dashboard/services/realtime.service.ts

// 实现订阅管理
subscribe(client: WebSocket, channel: string) {
  if (!this.channels.has(channel)) {
    this.channels.set(channel, new Set());
  }
  this.channels.get(channel)!.add(client);

  client.on('close', () => {
    this.channels.get(channel)?.delete(client);
  });
}

// 实现广播逻辑
broadcast(event: string, data: any) {
  const message = JSON.stringify({ event, data });

  for (const [channel, clients] of this.channels) {
    for (const client of clients) {
      if (client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    }
  }
}

// 实现心跳检测
startHeartbeat() {
  setInterval(() => {
    const message = JSON.stringify({ action: 'ping' });
    for (const [channel, clients] of this.channels) {
      for (const client of clients) {
        if (client.readyState === WebSocket.OPEN) {
          client.send(message);
        }
      }
    }
  }, 30000);
}
