export class MetricsCollector {
  private metrics: Map<string, any[]> = new Map();

  recordAgentExecution(agent: string, duration: number, tokens: number) {
    this.pushMetric('agent_execution', {
      agent,
      duration,
      tokens,
      timestamp: Date.now()
    });
  }

  recordAPICall(endpoint: string, duration: number, success: boolean) {
    this.pushMetric('api_call', {
      endpoint,
      duration,
      success,
      timestamp: Date.now()
    });
  }

  getMetrics(type: string, timeRange: string) {
    const metrics = this.metrics.get(type) || [];
    const { startTime } = this.parseTimeRange(timeRange);
    return metrics.filter(m => m.timestamp >= startTime);
  }
}
