// 1. 添加 Dashboard 依赖注入
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private dashboardServices?: any;

  constructor(config: IterationConfig) {
    // ...

    // 获取 Dashboard 服务(如果已启动)
    try {
      this.dashboardServices = getServices();
    } catch (e) {
      // Dashboard 未启动,忽略
    }
  }

  // 2. 在迭代开始时通知 Dashboard
  async start() {
    if (this.dashboardServices?.iterationService) {
      await this.dashboardServices.iterationService.create({
        iterationNumber: this.count,
        status: 'running',
        requirement: this.requirement,
        startedAt: new Date()
      });
    }

    // ... 原有逻辑
  }

  // 3. 在 Agent 执行时更新进度
  private async executeAgent(agent: BaseAgent, task: string) {
    if (this.dashboardServices?.realtimeService) {
      await this.dashboardServices.realtimeService.broadcastAgentStatusChange({
        agentName: agent.name,
        status: 'running',
        progress: 0,
        timestamp: new Date()
      });
    }

    // ... 执行 Agent 逻辑

    // 4. Agent 完成后更新
    if (this.dashboardServices?.realtimeService) {
      await this.dashboardServices.realtimeService.broadcastAgentStatusChange({
        agentName: agent.name,
        status: 'completed',
        progress: 100,
        timestamp: new Date()
      });
    }
  }

  // 5. 在迭代完成时更新状态
  private async completeIteration() {
    if (this.dashboardServices?.iterationService) {
      await this.dashboardServices.iterationService.update(iterationId, {
        status: 'completed',
        completedAt: new Date()
      });
    }
  }
}
```

